const body = $json.body || {};
const user_id = (body.user_id || '').trim();
const org_id = (body.org_id || '').trim();
if (!user_id) throw new Error('user_id is required');
if (!org_id) throw new Error('org_id is required');
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRe.test(user_id)) throw new Error('user_id must be a valid UUID');
if (!uuidRe.test(org_id)) throw new Error('org_id must be a valid UUID');
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
let token = 'ARKON-';
for (let i = 0; i < 8; i++) { token += chars[Math.floor(Math.random() * chars.length)]; }
const expires_at = new Date(Date.now() + 86400000).toISOString();
function esc(s) { return String(s).replace(/'/g, "''"); }
const sql = "UPDATE sc_orgs SET pending_verify_token = '" + esc(token) + "', pending_verify_expires_at = '" + expires_at + "'::timestamptz WHERE org_id = '" + org_id + "'::uuid RETURNING org_id, slug, name";
return [{ json: { user_id, org_id, token, expires_at, sql } }];

const init = $('Build Verify Init').first().json;
const dbRow = $input.first().json;
if (!dbRow.org_id) return [{ json: { ok: false, error: 'Org not found' } }];
return [{ json: { ok: true, token: init.token, expires_at: init.expires_at, org: { org_id: dbRow.org_id, slug: dbRow.slug, name: dbRow.name }, instructions: 'Paste the token into the Introduction box at https://robertsspaceindustries.com/en/orgs/' + dbRow.slug + '/admin/content then call verify/confirm' } }];

const body = $json.body || {};
const user_id = (body.user_id || '').trim();
const org_id = (body.org_id || '').trim();
if (!user_id) throw new Error('user_id is required');
if (!org_id) throw new Error('org_id is required');
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRe.test(user_id)) throw new Error('user_id must be a valid UUID');
if (!uuidRe.test(org_id)) throw new Error('org_id must be a valid UUID');
return [{ json: { user_id, org_id } }];

const confirmParams = $('Build Confirm Params').first().json;
const orgRow = $('DB Get Org For Confirm').first().json;
const rsiResp = $input.first().json || {};
const noop = 'SELECT 1 AS noop';
if (!orgRow.org_id) return [{ json: { ok: false, reason: 'org_not_found', sql_org: noop, sql_user: noop } }];
const token = orgRow.pending_verify_token;
if (!token) return [{ json: { ok: false, reason: 'no_pending_token', sql_org: noop, sql_user: noop } }];
const expiresAt = orgRow.pending_verify_expires_at;
if (expiresAt && new Date(expiresAt) < new Date()) return [{ json: { ok: false, reason: 'token_expired', sql_org: noop, sql_user: noop } }];
const html = typeof rsiResp === 'string' ? rsiResp : (rsiResp.data || rsiResp.body || JSON.stringify(rsiResp));
if (html.indexOf(token) === -1) return [{ json: { ok: false, reason: 'token_not_found', sql_org: noop, sql_user: noop } }];
const userId = confirmParams.user_id;
const orgId = confirmParams.org_id;
const now = new Date().toISOString();
const sql_org = "UPDATE sc_orgs SET verified_at = '" + now + "'::timestamptz, verified_by = '" + userId + "'::uuid, pending_verify_token = NULL, pending_verify_expires_at = NULL WHERE org_id = '" + orgId + "'::uuid";
const sql_user = "UPDATE users SET managed_org_id = '" + orgId + "'::uuid WHERE user_id = '" + userId + "'::uuid";
return [{ json: { ok: true, reason: 'verified', sql_org, sql_user } }];

const check = $('Check Token And Build SQL').first().json;
const params = $('Build Confirm Params').first().json;
if (!check.ok) {
  const msgs = { org_not_found: 'Org not found', no_pending_token: 'No token - call verify/init first', token_expired: 'Token expired - call verify/init', token_not_found: 'Token not found on RSI org page - check Introduction box' };
  return [{ json: { ok: false, verified: false, reason: check.reason, message: msgs[check.reason] || check.reason } }];
}
return [{ json: { ok: true, verified: true, org_id: params.org_id, user_id: params.user_id } }];
